/**
 * 轻量级依赖注入容器
 *
 * 统一管理服务实例的创建和生命周期，实现服务解耦。
 * 用于 server 包中管理 JobQueue、MapStorage、MapEngine 等服务。
 */

// eslint-disable-next-line @typescript-eslint/no-explicit-any
type Factory<T> = (...args: any[]) => T;

interface ServiceEntry<T = unknown> {
  factory: Factory<T>;
  instance?: T;
  singleton: boolean;
}

export class Container {
  private services = new Map<string, ServiceEntry>();

  /**
   * 注册一个瞬态服务（每次 resolve 都创建新实例）
   */
  register<T>(name: string, factory: Factory<T>): this {
    this.services.set(name, { factory, singleton: false });
    return this;
  }

  /**
   * 注册一个单例服务（首次 resolve 后缓存）
   */
  registerSingleton<T>(name: string, factory: Factory<T>): this {
    this.services.set(name, { factory, singleton: true });
    return this;
  }

  /**
   * 注册一个已存在的实例作为单例
   */
  registerInstance<T>(name: string, instance: T): this {
    this.services.set(name, {
      factory: () => instance,
      instance,
      singleton: true,
    });
    return this;
  }

  /**
   * 解析服务实例
   * @throws 如果服务未注册
   */
  resolve<T>(name: string): T {
    const entry = this.services.get(name);
    if (!entry) {
      throw new Error(`[Container] Service "${name}" not registered`);
    }

    if (entry.singleton && entry.instance !== undefined) {
      return entry.instance as T;
    }

    const instance = entry.factory() as T;

    if (entry.singleton) {
      entry.instance = instance;
    }

    return instance;
  }

  /**
   * 尝试解析服务，失败返回 undefined
   */
  tryResolve<T>(name: string): T | undefined {
    try {
      return this.resolve<T>(name);
    } catch {
      return undefined;
    }
  }

  /**
   * 检查服务是否已注册
   */
  has(name: string): boolean {
    return this.services.has(name);
  }

  /**
   * 重置容器（清除所有注册和缓存实例）
   */
  reset(): void {
    this.services.clear();
  }

  /**
   * 清除所有缓存实例（保留注册信息）
   * 下次 resolve 时会重新创建
   */
  clearInstances(): void {
    for (const entry of this.services.values()) {
      entry.instance = undefined;
    }
  }
}

/**
 * 创建默认的 server 容器
 */
export function createServerContainer(): Container {
  const container = new Container();

  // 服务注册在 createApp 中根据配置完成
  // 这里只返回空容器，由调用方决定注册哪些服务
  return container;
}

import type { Context } from 'hono';
import {
  MapGenException,
  errorCodeToHttpStatus,
  type MapGenError,
  type ErrorCode,
} from '@mapgen/shared-types';

/**
 * 集中式错误处理中间件
 *
 * 捕获所有未处理的异常，统一返回 JSON 格式的错误响应。
 * 支持 MapGenException（业务错误）和原生 Error（系统错误）。
 */
export function errorHandler() {
  return async (err: Error, c: Context) => {
    // 业务错误：已知的 MapGen 错误
    if (err instanceof MapGenException) {
      const { mapGenError } = err;
      const status = errorCodeToHttpStatus(mapGenError.code);
      return c.json(
        {
          ok: false,
          error: {
            code: mapGenError.code,
            message: mapGenError.message,
            details: mapGenError.details,
          },
        },
        status as any
      );
    }

    // 系统错误：未预期的异常
    console.error('[Server] Unhandled error:', err);
    return c.json(
      {
        ok: false,
        error: {
          code: 'SERVER_ERROR' as ErrorCode,
          message:
            process.env.NODE_ENV === 'production'
              ? 'Internal server error'
              : err.message,
        },
      },
      500
    );
  };
}

/**
 * 包装 Result 返回值为 HTTP 响应
 */
export function resultResponse<T>(result: { ok: true; value: T }): Response;
export function resultResponse<T>(result: {
  ok: false;
  error: MapGenError;
}): Response;
export function resultResponse<T>(
  result: { ok: true; value: T } | { ok: false; error: MapGenError }
): Response {
  if (result.ok) {
    return new Response(JSON.stringify({ ok: true, data: result.value }), {
      status: 200,
      headers: { 'Content-Type': 'application/json' },
    });
  }
  const status = errorCodeToHttpStatus(result.error.code);
  return new Response(
    JSON.stringify({ ok: false, error: result.error }),
    {
      status,
      headers: { 'Content-Type': 'application/json' },
    }
  );
}

import { z } from 'zod';
import type { MapParams } from './params.js';

// ── 约束常量 ──────────────────────────────────────────────

export const CONSTRAINTS = {
  minMapSize: 64,
  maxMapSize: 4096,
  minOctaves: 1,
  maxOctaves: 12,
  minPlates: 2,
  maxPlates: 64,
  minErosionIterations: 0,
  maxErosionIterations: 500,
  sizeWarningThreshold: 1024 * 1024,
} as const;

// ── 子 Schema ─────────────────────────────────────────────

const NoiseTypeSchema = z.enum(['perlin', 'simplex', 'value', 'worley']);
const FbmTypeSchema = z.enum(['standard', 'ridged', 'billowy', 'warped']);
const GenModeSchema = z.enum(['procedural', 'blank']);

// ── 主 Schema ─────────────────────────────────────────────

export const MapParamsSchema = z.object({
  seedStr: z.string().default(''),
  mapAspect: z.string().optional(),
  mapSize: z
    .number()
    .int()
    .min(CONSTRAINTS.minMapSize)
    .max(CONSTRAINTS.maxMapSize)
    .optional(),
  mapWidth: z
    .number()
    .int()
    .min(CONSTRAINTS.minMapSize)
    .max(CONSTRAINTS.maxMapSize)
    .optional(),
  mapHeight: z
    .number()
    .int()
    .min(CONSTRAINTS.minMapSize)
    .max(CONSTRAINTS.maxMapSize)
    .optional(),
  plateCount: z
    .number()
    .int()
    .min(CONSTRAINTS.minPlates)
    .max(CONSTRAINTS.maxPlates)
    .default(12),
  landmass: z.number().min(0).max(1).default(0.4),
  noiseType: NoiseTypeSchema.default('simplex'),
  fbmType: FbmTypeSchema.default('ridged'),
  octaves: z
    .number()
    .int()
    .min(CONSTRAINTS.minOctaves)
    .max(CONSTRAINTS.maxOctaves)
    .default(6),
  lacunarity: z.number().min(1.0).max(4.0).default(2.0),
  persistence: z.number().min(0.01).max(0.99).default(0.5),
  seaLevel: z.number().min(-1).max(1).default(0.0),
  mountainFold: z.number().min(0).max(1).default(0.5),
  coastDetail: z.number().min(0).max(1).default(0.5),
  erosionIterations: z
    .number()
    .int()
    .min(CONSTRAINTS.minErosionIterations)
    .max(CONSTRAINTS.maxErosionIterations)
    .default(30),
  erosionStrength: z.number().min(0).max(1).default(0.3),
  lakeDensity: z.number().min(0).max(1).default(0.02),
  riverCount: z.number().int().min(0).max(200).optional(),
  tempOffset: z.number().min(-1).max(1).default(0.0),
  snowLine: z.number().min(0).max(1).default(0.7),
  rainStrength: z.number().min(0).max(2).optional(),
  windDirX: z.number().min(-1).max(1).optional(),
  windDirY: z.number().min(-1).max(1).optional(),
  mode: GenModeSchema.optional(),
  enableOceanCurrents: z.boolean().optional(),
  enableIceSheet: z.boolean().optional(),
  enableMonsoon: z.boolean().optional(),
  enableContinentality: z.boolean().optional(),
  enableHadleyEnhancement: z.boolean().optional(),
  enableAdvancedBiomes: z.boolean().optional(),
  enableWatershed: z.boolean().optional(),
  enableVolcanism: z.boolean().optional(),
  enableSeasons: z.boolean().optional(),
});

// ── 验证结果类型 ──────────────────────────────────────────

export interface ValidationError {
  path: string;
  message: string;
  code: string;
}

export type ValidationResult<T> =
  | { ok: true; value: T; warnings: string[] }
  | { ok: false; errors: ValidationError[] };

// ── 跨字段警告（不阻止生成，但提示用户） ─────────────────

function checkWarnings(params: MapParams): string[] {
  const warnings: string[] = [];
  const w = params.mapWidth ?? params.mapSize ?? 512;
  const h = params.mapHeight ?? params.mapSize ?? 512;

  if (w * h > CONSTRAINTS.sizeWarningThreshold && params.octaves > 6) {
    warnings.push(
      `大尺寸 (${w}×${h}) + 高 octaves (${params.octaves}) 可能导致性能问题，建议降低 octaves 至 4-5`
    );
  }

  if (params.plateCount > 30) {
    warnings.push(
      `plateCount=${params.plateCount} 较高，可能导致生成变慢`
    );
  }

  if (params.erosionIterations > 100) {
    warnings.push(
      `erosionIterations=${params.erosionIterations} 较高，可能显著增加生成时间`
    );
  }

  return warnings;
}

// ── 验证函数 ──────────────────────────────────────────────

/**
 * 验证并规范化地图生成参数
 * - 严格模式：未知字段会被拒绝
 * - 返回规范化后的参数 + 跨字段警告
 */
export function validateParams(
  input: unknown
): ValidationResult<MapParams> {
  const result = MapParamsSchema.safeParse(input);

  if (!result.success) {
    const errors: ValidationError[] = result.error.issues.map((issue) => ({
      path: issue.path.join('.'),
      message: issue.message,
      code: issue.code,
    }));
    return { ok: false, errors };
  }

  const warnings = checkWarnings(result.data as MapParams);
  return { ok: true, value: result.data as MapParams, warnings };
}

/**
 * 用默认值填充部分参数（不验证，用于 UI 预设合并）
 */
export function normalizeParams(input: Partial<MapParams>): MapParams {
  return MapParamsSchema.parse(input) as MapParams;
}

import { Hono } from 'hono';
import { cors } from 'hono/cors';
import { loadConfig } from './config.js';
import { createDatabase } from './db/index.js';
import { jobQueue } from './services/jobQueue.js';
import { executeGenerationJob } from './services/mapEngine.js';
import { MapStorage } from './services/mapStorage.js';
import { Container } from './container.js';
import { errorHandler } from './middleware/error.js';
import { createHealthRoute } from './routes/health.js';
import { createGenerateRoute } from './routes/generate.js';
import { createJobsRoute } from './routes/jobs.js';
import { createMapsRoute } from './routes/maps.js';
import { createPresetsRoute } from './routes/presets.js';

/**
 * 创建应用实例（工厂模式，支持依赖注入和测试）
 */
export function createApp(deps?: { container?: Container }) {
  const config = loadConfig();
  const db = createDatabase();
  const storage = new MapStorage(db);

  // DI 容器
  const container = deps?.container ?? new Container();
  container.registerInstance('config', config);
  container.registerInstance('db', db);
  container.registerInstance('storage', storage);
  container.registerInstance('jobQueue', jobQueue);

  jobQueue.setExecutor(executeGenerationJob);

  const app = new Hono();

  // 全局中间件
  app.use('*', cors({ origin: config.corsOrigins }));

  // 路由
  app.route('/api/v1', createHealthRoute(config));
  app.route('/api/v1', createGenerateRoute());
  app.route('/api/v1', createJobsRoute());
  app.route('/api/v1', createMapsRoute(storage));
  app.route('/api/v1', createPresetsRoute(db));

  // 集中式错误处理（必须在路由之后）
  app.onError(errorHandler());

  return { app, container, config };
}

// 直接启动
const { app, config } = createApp();

export default app;

if (typeof Bun !== 'undefined' && import.meta.url === `file://${Bun.main}`) {
  const port = config.port;
  Bun.serve({ fetch: app.fetch, port });
  console.log(`MapGen server listening on http://localhost:${port}`);
}

import { Hono } from 'hono';
import { jobQueue } from '../services/jobQueue.js';
import { validateParams, createError, MapGenException } from '@mapgen/shared-types';
import type { GenerateRequest } from '@mapgen/shared-types';

export function createGenerateRoute(): Hono {
  const app = new Hono();

  /**
   * POST /generate?sync=true — 同步生成（等待完成后返回完整地图数据）
   * POST /generate          — 异步生成（返回 jobId，轮询 /jobs/:id 获取结果）
   */
  app.post('/generate', async c => {
    const body = await c.req.json<GenerateRequest>();

    // Zod 验证输入参数
    const validation = validateParams(body.params);
    if (!validation.ok) {
      throw new MapGenException(
        createError('VALIDATION_ERROR', '参数验证失败', {
          errors: validation.errors,
        })
      );
    }

    const sync = c.req.query('sync') === 'true';

    if (sync) {
      // 同步模式：直接执行生成并返回结果
      const { executeGenerationJob } = await import('../services/mapEngine.js');
      const syncJob = {
        id: `sync-${Date.now()}`,
        status: 'queued' as 'queued' | 'running' | 'completed' | 'failed',
        params: validation.value,
        progress: 0,
        phase: 'queued',
        createdAt: Date.now(),
      };
      executeGenerationJob(syncJob as any);
      if (syncJob.status === 'failed') {
        throw new MapGenException(
          createError('GENERATION_FAILED', '生成失败')
        );
      }
      return c.json({ ok: true, jobId: syncJob.id, data: (syncJob as any).result }, 200);
    }

    // 异步模式：加入队列
    const jobId = jobQueue.create(validation.value);
    return c.json({ jobId, status: 'queued' as const }, 202);
  });

  return app;
}

import { Hono } from 'hono';
import { jobQueue } from '../services/jobQueue.js';
import {
  createError,
  MapGenException,
  type GenerationProgress,
  type GenerationResult,
  type MapGenError,
} from '@mapgen/shared-types';

export function createJobsRoute(): Hono {
  const app = new Hono();

  /**
   * GET /jobs — 列出所有任务
   */
  app.get('/jobs', c => {
    const jobs = jobQueue.list();
    return c.json({ ok: true, data: jobs });
  });

  /**
   * GET /jobs/:id — 获取任务详情（支持 SSE）
   */
  app.get('/jobs/:id', c => {
    const id = c.req.param('id');
    const accept = c.req.header('accept') || '';
    const job = jobQueue.get(id);

    if (!job) {
      throw new MapGenException(
        createError('JOB_NOT_FOUND', `任务 ${id} 不存在`)
      );
    }

    if (accept.includes('text/event-stream')) {
      return new Response(
        new ReadableStream({
          start(controller) {
            const encoder = new TextEncoder();
            const send = (event: string, data: unknown): void => {
              controller.enqueue(
                encoder.encode(`event: ${event}\ndata: ${JSON.stringify(data)}\n\n`)
              );
            };

            job.onProgress = (progress: GenerationProgress) =>
              send('progress', progress);
            job.onComplete = (result: GenerationResult) => {
              send('completed', { jobId: job.id, result });
              controller.close();
            };
            job.onFail = (error: MapGenError) => {
              send('failed', { jobId: job.id, error });
              controller.close();
            };

            if (job.status === 'completed' && job.result) {
              job.onComplete(job.result);
            } else if (job.status === 'failed' && job.error) {
              job.onFail(job.error);
            }
          },
        }),
        {
          headers: {
            'Content-Type': 'text/event-stream',
            'Cache-Control': 'no-cache',
            Connection: 'keep-alive',
          },
        }
      );
    }

    return c.json({
      jobId: job.id,
      status: job.status,
      progress: {
        jobId: job.id,
        phase: job.phase,
        fraction: job.progress,
        phaseLabel: job.phase,
      },
      result: job.result,
      error: job.error,
    });
  });

  /**
   * DELETE /jobs/:id — 取消/删除任务
   */
  app.delete('/jobs/:id', c => {
    const id = c.req.param('id');
    const removed = jobQueue.cancel(id);
    if (!removed) {
      throw new MapGenException(
        createError('JOB_NOT_FOUND', `任务 ${id} 不存在或已完成`)
      );
    }
    return c.json({ ok: true, message: `任务 ${id} 已取消` });
  });

  return app;
}

import { randomUUID } from 'node:crypto';
import type {
  MapParams,
  GenerationResult,
  GenerationProgress,
  MapGenError,
} from '@mapgen/shared-types';

export type JobStatus = 'queued' | 'running' | 'completed' | 'failed';

export interface Job {
  id: string;
  status: JobStatus;
  params: MapParams;
  progress: number;
  phase: string;
  result?: GenerationResult;
  error?: MapGenError;
  createdAt: number;
  completedAt?: number;
  onProgress?: (progress: GenerationProgress) => void;
  onComplete?: (result: GenerationResult) => void;
  onFail?: (error: MapGenError) => void;
}

export interface JobQueueOptions {
  maxConcurrent?: number;
  maxHistory?: number;
}

class JobQueue {
  private jobs = new Map<string, Job>();
  private queue: string[] = [];
  private activeCount = 0;
  private maxConcurrent: number;
  private maxHistory: number;
  private executor?: (job: Job) => void | Promise<void>;

  constructor(options: JobQueueOptions = {}) {
    this.maxConcurrent = options.maxConcurrent ?? 1;
    this.maxHistory = options.maxHistory ?? 100;
  }

  create(params: MapParams): string {
    const id = randomUUID();
    const job: Job = {
      id,
      status: 'queued',
      params,
      progress: 0,
      phase: 'queued',
      createdAt: Date.now(),
    };
    this.jobs.set(id, job);
    this.queue.push(id);
    this.cleanupOldJobs();
    void this.process();
    return id;
  }

  get(id: string): Job | undefined {
    return this.jobs.get(id);
  }

  setExecutor(executor: (job: Job) => void | Promise<void>): void {
    this.executor = executor;
  }

  getStats(): { queued: number; running: number; completed: number; failed: number } {
    let queued = 0;
    let running = 0;
    let completed = 0;
    let failed = 0;
    for (const job of this.jobs.values()) {
      switch (job.status) {
        case 'queued':
          queued++;
          break;
        case 'running':
          running++;
          break;
        case 'completed':
          completed++;
          break;
        case 'failed':
          failed++;
          break;
      }
    }
    return { queued, running, completed, failed };
  }

  /**
   * 列出所有任务（摘要信息）
   */
  list(): Array<{
    id: string;
    status: JobStatus;
    progress: number;
    phase: string;
    createdAt: number;
    completedAt?: number;
  }> {
    const result: Array<{
      id: string;
      status: JobStatus;
      progress: number;
      phase: string;
      createdAt: number;
      completedAt?: number;
    }> = [];
    for (const job of this.jobs.values()) {
      result.push({
        id: job.id,
        status: job.status,
        progress: job.progress,
        phase: job.phase,
        createdAt: job.createdAt,
        completedAt: job.completedAt,
      });
    }
    return result;
  }

  /**
   * 取消/删除任务
   * @returns true 如果任务被成功取消
   */
  cancel(id: string): boolean {
    const job = this.jobs.get(id);
    if (!job) return false;

    // 从队列中移除
    const queueIdx = this.queue.indexOf(id);
    if (queueIdx !== -1) {
      this.queue.splice(queueIdx, 1);
    }

    // 如果正在运行，标记为失败
    if (job.status === 'running') {
      job.status = 'failed';
      job.error = { code: 'GENERATION_ABORTED', message: '任务已取消' };
      job.completedAt = Date.now();
      if (job.onFail) job.onFail(job.error);
    }

    // 删除任务记录
    this.jobs.delete(id);
    return true;
  }

  private async process(): Promise<void> {
    while (this.activeCount < this.maxConcurrent && this.queue.length > 0) {
      const id = this.queue.shift();
      if (!id) continue;
      const job = this.jobs.get(id);
      if (!job) continue;
      job.status = 'running';
      this.activeCount++;
      this.executeJob(job);
    }
  }

  private async executeJob(job: Job): Promise<void> {
    try {
      if (this.executor) {
        await this.executor(job);
      }
    } catch (e) {
      if (job.status !== 'failed') {
        job.status = 'failed';
        job.error = { code: 'GENERATION_FAILED', message: String(e) };
        job.completedAt = Date.now();
        if (job.onFail) job.onFail(job.error);
      }
    } finally {
      this.activeCount--;
      void this.process();
    }
  }

  private cleanupOldJobs(): void {
    if (this.jobs.size <= this.maxHistory) return;

    const completedJobs: Job[] = [];
    for (const job of this.jobs.values()) {
      if (job.status === 'completed' || job.status === 'failed') {
        completedJobs.push(job);
      }
    }

    completedJobs.sort((a, b) => (a.completedAt ?? 0) - (b.completedAt ?? 0));
    const toRemove = completedJobs.slice(
      0,
      completedJobs.length - this.maxHistory + this.jobs.size - this.maxHistory
    );
    for (const job of toRemove) {
      this.jobs.delete(job.id);
    }
  }
}

export const jobQueue = new JobQueue({ maxConcurrent: 2, maxHistory: 200 });

export type ErrorCode =
  | 'VALIDATION_ERROR'
  | 'JOB_NOT_FOUND'
  | 'GENERATION_FAILED'
  | 'GENERATION_ABORTED'
  | 'OUT_OF_MEMORY'
  | 'MAP_NOT_FOUND'
  | 'CHECKPOINT_NOT_FOUND'
  | 'STORAGE_ERROR'
  | 'STORAGE_QUOTA_EXCEEDED'
  | 'NETWORK_ERROR'
  | 'TIMEOUT'
  | 'BACKEND_UNAVAILABLE'
  | 'SERVER_ERROR'
  | 'PRESET_NOT_FOUND'
  | 'PRESET_IN_USE';

export interface MapGenError {
  code: ErrorCode;
  message: string;
  details?: Record<string, unknown>;
}

/** Result 类型 - 强制调用方处理错误 */
export type Result<T, E = MapGenError> = { ok: true; value: T } | { ok: false; error: E };

export function ok<T>(value: T): Result<T> {
  return { ok: true, value };
}

export function err<E extends MapGenError>(error: E): Result<never, E> {
  return { ok: false, error };
}

/**
 * 从 Result 中提取值，失败时抛出 MapGenException
 * @example
 * const data = unwrap(await engine.generate(params));
 */
export function unwrap<T>(result: Result<T>): T {
  if (result.ok) return result.value;
  throw new MapGenException(result.error);
}

/**
 * 创建标准化错误对象的工厂函数
 */
export function createError(
  code: ErrorCode,
  message: string,
  details?: Record<string, unknown>
): MapGenError {
  return { code, message, details };
}

/**
 * MapGenException - 将 MapGenError 包装为原生 Error
 * 用于需要抛出异常的场景（如 unwrap）
 */
export class MapGenException extends Error {
  public readonly mapGenError: MapGenError;

  constructor(error: MapGenError) {
    super(error.message);
    this.name = 'MapGenException';
    this.mapGenError = error;
  }

  toJSON(): MapGenError {
    return this.mapGenError;
  }
}

/**
 * 将 HTTP 状态码映射到 ErrorCode
 */
export function errorCodeToHttpStatus(code: ErrorCode): number {
  const map: Record<ErrorCode, number> = {
    VALIDATION_ERROR: 400,
    JOB_NOT_FOUND: 404,
    MAP_NOT_FOUND: 404,
    CHECKPOINT_NOT_FOUND: 404,
    PRESET_NOT_FOUND: 404,
    PRESET_IN_USE: 409,
    GENERATION_FAILED: 500,
    GENERATION_ABORTED: 400,
    OUT_OF_MEMORY: 507,
    STORAGE_ERROR: 500,
    STORAGE_QUOTA_EXCEEDED: 507,
    NETWORK_ERROR: 502,
    TIMEOUT: 504,
    BACKEND_UNAVAILABLE: 503,
    SERVER_ERROR: 500,
  };
  return map[code] ?? 500;
}

